import type { ActivityType, MealType } from '@motivation/shared';

export function activityIcon(type: ActivityType): string {
    switch (type) {
        case 'gym': return '🏋️';
        case 'tennis': return '🎾';
        case 'ice-skating': return '⛸️';
        case 'running': return '🏃';
        case 'cycling': return '🚴';
        case 'swimming': return '🏊';
        case 'walking': return '🚶';
        default: return '💪';
    }
}

export function getDefaultMealType(): MealType {
    const hour = Temporal.Now.plainTimeISO().hour;
    if (hour < 11) return 'Breakfast';
    if (hour < 15) return 'Lunch';
    if (hour < 21) return 'Dinner';
    return 'Snacks';
}
